void Sort(Student *list, int count, bool(*BiggerFnc)(Student &s1, Student &s2) ) {
bool sorted;
do { sorted = true;
for (int tr = 0; tr < count - 1; tr++)
{ if (BiggerFnc(list[tr], list[tr + 1]))
{ Student aux = list[tr];
list[tr] = list[tr + 1];
list[tr + 1] = aux;
sorted = false;
}
}
} while (!sorted);
}

